/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email settings; designed to accommodate
 * additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * User notification preferences stored per user.
 */
export interface UserNotificationPreferences {
  /** Same as the user's ID */
  id: string;
  /** The user this preferences record belongs to */
  userId: string;
  /** Global email toggle — when false, no emails are sent */
  emailEnabled: boolean;
  /** How often email notifications are delivered */
  emailFrequency: EmailFrequency;
  /** Which notification categories the user is subscribed to */
  subscribedCategories: NotificationType[];
  /** When the preferences were last updated */
  updatedAt: Date;
}

/**
 * Input for updating notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types — used as the default subscribed set.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'user-welcome',
  'user-profile-update',
];

/**
 * Create default preferences for a user (everything enabled, immediate delivery).
 */
export function createDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    id: userId,
    userId,
    emailEnabled: true,
    emailFrequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    updatedAt: new Date(),
  };
}

/**
 * Repository for UserNotificationPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Uses userId as the record ID for easy lookup.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled: record['emailEnabled'] as boolean,
      emailFrequency: record['emailFrequency'] as UserNotificationPreferences['emailFrequency'],
      subscribedCategories: JSON.parse(record['subscribedCategories'] as string) as NotificationType[],
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      subscribedCategories: JSON.stringify(entity.subscribedCategories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    return this.findById(userId);
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences and a
 * shouldNotify() check used by NotificationService before dispatch.
 *
 * Default behavior: if no preferences exist for a user, all notifications
 * are enabled with immediate delivery — preserving existing behavior.
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType } from '../models/notification.js';
import type { UserNotificationPreferences, UpdatePreferencesInput } from '../models/user-preferences.js';
import { createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns default preferences if none exist.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Get preferences for a user, or undefined if none have been explicitly set.
   */
  getExplicitPreferences(userId: string): UserNotificationPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Update preferences for a user. Creates default preferences first if none exist.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (!existing) {
      const defaults = createDefaultPreferences(userId);
      const merged: UserNotificationPreferences = {
        ...defaults,
        ...input,
        id: userId,
        userId,
        updatedAt: new Date(),
      };
      // subscribedCategories needs explicit handling since spread may not work as expected
      if (input.subscribedCategories !== undefined) {
        merged.subscribedCategories = input.subscribedCategories;
      }
      this.preferencesRepository.save(merged);
      this.logger.info(`Created preferences for user: ${userId}`);
      return merged;
    }

    const updated: UserNotificationPreferences = {
      ...existing,
      ...(input.emailEnabled !== undefined ? { emailEnabled: input.emailEnabled } : {}),
      ...(input.emailFrequency !== undefined ? { emailFrequency: input.emailFrequency } : {}),
      ...(input.subscribedCategories !== undefined ? { subscribedCategories: input.subscribedCategories } : {}),
      updatedAt: new Date(),
    };

    this.preferencesRepository.update(userId, updated);
    this.logger.info(`Updated preferences for user: ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user based on their preferences.
   *
   * Returns true if:
   * - No explicit preferences exist (default: all enabled)
   * - Email is globally enabled AND the notification type is in subscribed categories
   */
  shouldNotify(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences set — default is to notify
    if (!prefs) {
      return true;
    }

    // Global email toggle
    if (!prefs.emailEnabled) {
      this.logger.debug(`Email disabled for user: ${userId}`);
      return false;
    }

    // Category check
    if (!prefs.subscribedCategories.includes(notificationType)) {
      this.logger.debug(`User ${userId} not subscribed to ${notificationType}`);
      return false;
    }

    return true;
  }

  /**
   * Delete preferences for a user (resets to defaults).
   */
  deletePreferences(userId: string): boolean {
    return this.preferencesRepository.delete(userId);
  }
}

