import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import { ALL_NOTIFICATION_TYPES, createDefaultPreferences } from '../../src/models/user-preferences.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
  });

  describe('getPreferences', () => {
    it('should return default preferences when none exist', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
    });

    it('should return stored preferences when they exist', () => {
      service.updatePreferences('user-1', { emailEnabled: false });
      const prefs = service.getPreferences('user-1');
      expect(prefs.emailEnabled).toBe(false);
    });
  });

  describe('getExplicitPreferences', () => {
    it('should return undefined when no preferences have been set', () => {
      expect(service.getExplicitPreferences('user-1')).toBeUndefined();
    });

    it('should return preferences when explicitly set', () => {
      service.updatePreferences('user-1', { emailFrequency: 'daily-digest' });
      const prefs = service.getExplicitPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.emailFrequency).toBe('daily-digest');
    });
  });

  describe('updatePreferences', () => {
    it('should create preferences with defaults when none exist', () => {
      const prefs = service.updatePreferences('user-1', { emailFrequency: 'weekly-digest' });
      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('weekly-digest');
      expect(prefs.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
    });

    it('should update only the provided fields', () => {
      service.updatePreferences('user-1', { emailEnabled: true });
      const prefs = service.updatePreferences('user-1', { emailFrequency: 'daily-digest' });
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('daily-digest');
    });

    it('should update subscribed categories', () => {
      const prefs = service.updatePreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      expect(prefs.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should allow disabling email globally', () => {
      const prefs = service.updatePreferences('user-1', { emailEnabled: false });
      expect(prefs.emailEnabled).toBe(false);
    });

    it('should set updatedAt timestamp', () => {
      const before = new Date();
      const prefs = service.updatePreferences('user-1', { emailEnabled: true });
      expect(prefs.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });
  });

  describe('shouldNotify', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.updatePreferences('user-1', {
        emailEnabled: true,
        subscribedCategories: ['order-confirmation', 'user-welcome'],
      });
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.updatePreferences('user-1', { emailEnabled: false });
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      service.updatePreferences('user-1', {
        subscribedCategories: ['order-confirmation'],
      });
      expect(service.shouldNotify('user-1', 'order-status-update')).toBe(false);
    });

    it('should return false when email disabled even if category is subscribed', () => {
      service.updatePreferences('user-1', {
        emailEnabled: false,
        subscribedCategories: ALL_NOTIFICATION_TYPES,
      });
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(false);
    });
  });

  describe('deletePreferences', () => {
    it('should remove stored preferences', () => {
      service.updatePreferences('user-1', { emailEnabled: false });
      service.deletePreferences('user-1');
      expect(service.getExplicitPreferences('user-1')).toBeUndefined();
    });

    it('should return false when no preferences exist to delete', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });

    it('should cause shouldNotify to return true again (defaults)', () => {
      service.updatePreferences('user-1', { emailEnabled: false });
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(false);
      service.deletePreferences('user-1');
      expect(service.shouldNotify('user-1', 'order-confirmation')).toBe(true);
    });
  });
});

describe('createDefaultPreferences', () => {
  it('should create preferences with all categories enabled', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.id).toBe('user-1');
    expect(prefs.userId).toBe('user-1');
    expect(prefs.emailEnabled).toBe(true);
    expect(prefs.emailFrequency).toBe('immediate');
    expect(prefs.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let prefsRepo: PreferencesRepository;
  let prefsService: PreferencesService;
  let eventBus: EventBus;
  let notifService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    prefsRepo = new PreferencesRepository(db);
    prefsService = new PreferencesService(prefsRepo);
    eventBus = new EventBus();
    notifService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notifService.registerAdapter(emailAdapter);
    notifService.setPreferencesService(prefsService);
    resetNotificationIdCounter();
  });

  it('should send notifications when no preferences are set', async () => {
    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } as OrderCreatedEvent);

    expect(notifService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress notifications when email is globally disabled', async () => {
    prefsService.updatePreferences('user-1', { emailEnabled: false });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } as OrderCreatedEvent);

    expect(notifService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    prefsService.updatePreferences('user-1', {
      subscribedCategories: ['order-status-update'],
    });

    await eventBus.emit({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } as OrderCreatedEvent);

    // order-confirmation should be suppressed
    expect(notifService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should allow notifications for subscribed categories', async () => {
    prefsService.updatePreferences('user-1', {
      subscribedCategories: ['user-welcome'],
    });

    await eventBus.emit({
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } as UserCreatedEvent);

    expect(notifService.getNotificationCount()).toBe(1);
    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should work without preferences service (backward compatible)', async () => {
    const bareService = new NotificationService(eventBus);
    bareService.registerAdapter(emailAdapter);
    emailAdapter.clearSentEmails();

    await eventBus.emit({
      type: 'user:created',
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    } as UserCreatedEvent);

    // Both services handle the event (original + bare), but bare should have sent
    const emails = emailAdapter.getSentEmails();
    expect(emails.length).toBeGreaterThanOrEqual(1);
  });
});

